Here are the public test cases for feature11_commonmark_output_format:
{
  "description": "Render parsed Markdown back to normalized CommonMark, respecting configured bullet markers and line-wrapping width.",
  "cases": [
    {
      "input": {
        "markdown": "+ a\n",
        "format": "commonmark",
        "render": {
          "list_marker": "dash"
        }
      },
      "expected_output": "- a\n"
    }
  ]
}

Here are the public test cases for feature13_smart_punctuation:
{
  "description": "When smart punctuation is enabled, replace straight quotes, apostrophes, ellipses, en dashes, and em dashes with typographic characters during HTML rendering.",
  "cases": [
    {
      "input": {
        "markdown": "Why 'hello' \"there\". It's good.",
        "parse": {
          "smart_punctuation": true
        }
      },
      "expected_output": "<p>Why ‘hello’ “there”. It’s good.</p>\n"
    }
  ]
}

Here are the public test cases for feature2_inline_text_and_links:
{
  "description": "Render inline Markdown syntax and character references to HTML while preserving escaped literals and encoding link targets.",
  "cases": [
    {
      "input": {
        "markdown": "Some `code\\` yep.\n"
      },
      "expected_output": "<p>Some <code>code\\</code> yep.</p>\n"
    }
  ]
}

Here are the public test cases for feature3_raw_html_rendering:
{
  "description": "Render raw HTML according to safety options, allowing recognized raw blocks when unsafe output is enabled and filtering disallowed tag names when requested.",
  "cases": [
    {
      "input": {
        "markdown": "<script>\n*ok* </script> *ok*\n\n*ok*\n",
        "render": {
          "unsafe_html": true
        }
      },
      "expected_output": "<script>\n*ok* </script> *ok*\n<p><em>ok</em></p>\n"
    }
  ]
}

Here are the public test cases for feature5_task_list_extension:
{
  "description": "When task-list parsing is enabled, convert list items beginning with checkbox markers into disabled checkbox inputs, preserving checked state and inline markup.",
  "cases": [
    {
      "input": {
        "markdown": "- [ ] List item 1\n- [ ] This list item is **bold**\n- [x] There is some `code` here\n",
        "extensions": [
          "task_list"
        ],
        "render": {
          "unsafe_html": true
        }
      },
      "expected_output": "<ul>\n<li><input type=\"checkbox\" disabled=\"\" /> List item 1</li>\n<li><input type=\"checkbox\" disabled=\"\" /> This list item is <strong>bold</strong></li>\n<li><input type=\"checkbox\" checked=\"\" disabled=\"\" /> There is some <code>code</code> here</li>\n</ul>\n"
    }
  ]
}

Here are the public test cases for feature6_inline_extension_markup:
{
  "description": "When optional inline extensions are enabled, render strikethrough and superscript delimiters as semantic HTML while leaving surrounding punctuation intact.",
  "cases": [
    {
      "input": {
        "markdown": "This is ~strikethrough~.\n\nAs is ~~this, okay~~?\n",
        "extensions": [
          "strikethrough"
        ]
      },
      "expected_output": "<p>This is <del>strikethrough</del>.</p>\n<p>As is <del>this, okay</del>?</p>\n"
    }
  ]
}

Here are the public test cases for feature7_autolink_extension:
{
  "description": "When automatic link detection is enabled, convert bare web addresses and email addresses into links and leave malformed address-like text unchanged.",
  "cases": [
    {
      "input": {
        "markdown": "www.autolink.com\n",
        "extensions": [
          "autolink"
        ]
      },
      "expected_output": "<p><a href=\"http://www.autolink.com\">www.autolink.com</a></p>\n"
    }
  ]
}

Here are the public test cases for feature8_heading_anchor_extension:
{
  "description": "When heading anchors are enabled, prepend each heading with an anchor whose fragment is derived from normalized heading text and made unique for repeated headings.",
  "cases": [
    {
      "input": {
        "markdown": "# Hi.\n## Hi 1.\n### Hi.\n#### Hello.\n##### Hi.\n###### Hello.\n# Isn't it grand?",
        "extensions": [
          "header_id_anchors"
        ]
      },
      "expected_output": "<h1><a href=\"#hi\" aria-hidden=\"true\" class=\"anchor\" id=\"user-content-hi\"></a>Hi.</h1>\n<h2><a href=\"#hi-1\" aria-hidden=\"true\" class=\"anchor\" id=\"user-content-hi-1\"></a>Hi 1.</h2>\n<h3><a href=\"#hi-2\" aria-hidden=\"true\" class=\"anchor\" id=\"user-content-hi-2\"></a>Hi.</h3>\n<h4><a href=\"#hello\" aria-hidden=\"true\" class=\"anchor\" id=\"user-content-hello\"></a>Hello.</h4>\n<h5><a href=\"#hi-3\" aria-hidden=\"true\" class=\"anchor\" id=\"user-content-hi-3\"></a>Hi.</h5>\n<h6><a href=\"#hello-1\" aria-hidden=\"true\" class=\"anchor\" id=\"user-content-hello-1\"></a>Hello.</h6>\n<h1><a href=\"#isnt-it-grand\" aria-hidden=\"true\" class=\"anchor\" id=\"user-content-isnt-it-grand\"></a>Isn't it grand?</h1>\n"
    }
  ]
}

Here are the public test cases for feature9_footnote_extension:
{
  "description": "When footnote parsing is enabled, render valid references as numbered superscript links, append only referenced definitions, create backreferences, and leave invalid footnote syntax as ordinary text.",
  "cases": [
    {
      "input": {
        "markdown": "Here's my footnote![^a]\n\n[^a]: Yep.\n",
        "extensions": [
          "footnotes"
        ]
      },
      "expected_output": "<p>Here's my footnote!<sup class=\"footnote-ref\"><a href=\"#fn-a\" id=\"fnref-a\" data-footnote-ref>1</a></sup></p>\n<section class=\"footnotes\" data-footnotes>\n<ol>\n<li id=\"fn-a\">\n<p>Yep. <a href=\"#fnref-a\" class=\"footnote-backref\" data-footnote-backref data-footnote-backref-idx=\"1\" aria-label=\"Back to reference 1\">↩</a></p>\n</li>\n</ol>\n</section>\n"
    }
  ]
}
